    const filePath = task.filePath ?? relative(this.options.dataDir, generatedAbsolutePath).replace(/\\/g, "/");
    this.db.query(`UPDATE memory_task_canvases SET file_path = ? WHERE id = ?`).run(filePath, id);
    const absolutePath = task.filePath ? join(this.options.dataDir, task.filePath) : generatedAbsolutePath;
    await mkdir(dirname2(absolutePath), { recursive: true });
    await writeFile(absolutePath, `graph LR
  task_${id}["${task.label.replace(/"/g, "\\\"")}"]
`, "utf8");
    return {
      id,
      chatId: task.chatId,
      userId: task.userId,
      label: task.label,
      filePath,
      status,
      createdAt,
      updatedAt: createdAt
    };
