        sessionKey: sessionKey2(input.chatId, input.userId),
        sessionId: input.chatId,
        chatId: input.chatId,
        userId: input.userId,
        role: "user",
        messageText: input.content,
        recordedAt,
        timestamp: Date.parse(recordedAt) || eventId,
        metadata: input.mode ? { mode: input.mode } : {}
