class ToolRegistry {
  db;
  tools = new Map;
  constructor(db2) {
    this.db = db2;
  }
  register(tool) {
    this.tools.set(tool.name, tool);
    this.db.query(`
        INSERT INTO tool_registry (name, source, description, input_schema_json, enabled, updated_at)
        VALUES (?, ?, ?, ?, 1, ?)
        ON CONFLICT(name) DO UPDATE SET
          source = excluded.source,
          description = excluded.description,
          input_schema_json = excluded.input_schema_json,
          updated_at = excluded.updated_at
      `).run(tool.name, tool.source, tool.description, JSON.stringify(tool.inputSchema), nowIso());
  }
  registerMany(tools) {
    for (const tool of tools)
      this.register(tool);
  }
  list() {
    return [...this.tools.values()].map((tool) => ({
      name: tool.name,
      description: tool.description,
      inputSchema: tool.inputSchema
    }));
  }
  listDebug() {
    return [...this.tools.values()].map((tool) => ({
      name: tool.name,
      source: tool.source,
      description: tool.description
    }));
  }
  async call(name, args, ctx) {
    const tool = this.tools.get(name);
    if (!tool)
      return `Tool not found: ${name}`;
    try {
      return await tool.execute(args, ctx);
    } catch (error3) {
      return `Tool ${name} failed: ${error3 instanceof Error ? error3.message : String(error3)}`;
    }
  }
}

