var AUTONOMOUS_JOB_COLUMNS = `
          id,
          chat_id,
          user_id,
          prompt,
          job_type,
          message_text,
          agent_prompt,
          run_at_unix,
          run_count,
          max_runs,
          enabled,
          schedule_mode,
          interval_sec,
          cron_expr,
          last_run_at,
          last_finished_at,
          last_status,
          last_error,
          created_at,
          updated_at`;
function toUnixAnchor(createdAt, lastFinishedAt) {
  return lastFinishedAt ?? Math.floor(new Date(createdAt).getTime() / 1000);
}
function toSchedule(row) {
  return normalizeSchedule({
    scheduleMode: row.schedule_mode,
    runAtUnix: row.run_at_unix,
    intervalSec: row.interval_sec,
    cronExpr: row.cron_expr,
    lastFinishedAt: row.last_finished_at
  });
}
function mapRow(row) {
  const schedule = toSchedule(row);
  return {
    id: row.id,
    chatId: row.chat_id,
    userId: row.user_id,
    prompt: row.prompt,
    jobType: row.job_type,
    messageText: row.message_text,
    agentPrompt: row.agent_prompt,
    runAtUnix: schedule.runAtUnix,
    runCount: row.run_count,
    maxRuns: row.max_runs,
    enabled: row.enabled === 1,
    scheduleMode: schedule.scheduleMode,
    intervalSec: schedule.intervalSec,
    cronExpr: schedule.cronExpr,
    lastRunAt: row.last_run_at,
    lastFinishedAt: row.last_finished_at,
    lastStatus: row.last_status,
    lastError: row.last_error,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
    scheduleLabel: describeSchedule(schedule)
  };
}

class AutonomousJobService {
  db;
  constructor(db2) {
    this.db = db2;
  }
  createJob(input) {
    const schedule = normalizeSchedule(input.schedule);
    const maxRuns = input.maxRuns ?? (schedule.scheduleMode === "once" ? 1 : null);
    const now = nowIso();
    const result = this.db.query(`INSERT INTO autonomous_jobs (
          chat_id,
          user_id,
          prompt,
          job_type,
          message_text,
          agent_prompt,
          run_at_unix,
          run_count,
          max_runs,
          schedule_mode,
          interval_sec,
          cron_expr,
          enabled,
          last_run_at,
          last_finished_at,
          last_status,
          last_error,
          created_at,
          updated_at
        ) VALUES (?, ?, ?, ?, ?, ?, ?, 0, ?, ?, ?, ?, 1, NULL, NULL, NULL, NULL, ?, ?)`).run(input.chatId, input.userId, input.prompt, input.jobType ?? "agent", input.messageText ?? "", input.agentPrompt ?? "", schedule.runAtUnix, maxRuns, schedule.scheduleMode, schedule.intervalSec, schedule.cronExpr, now, now);
    const job = this.getJobById(Number(result.lastInsertRowid));
    if (!job)
      throw new Error("Failed to load created autonomous job");
    return job;
  }
  getJobById(id) {
    const row = this.db.query(`SELECT${AUTONOMOUS_JOB_COLUMNS}
         FROM autonomous_jobs
         WHERE id = ?`).get(id);
    return row ? mapRow(row) : null;
  }
  getJobByChat(chatId, id) {
    const row = this.db.query(`SELECT${AUTONOMOUS_JOB_COLUMNS}
         FROM autonomous_jobs
         WHERE chat_id = ? AND id = ?`).get(chatId, id);
    return row ? mapRow(row) : null;
  }
  listJobsForChat(chatId) {
    const rows = this.db.query(`SELECT${AUTONOMOUS_JOB_COLUMNS}
         FROM autonomous_jobs
         WHERE chat_id = ?
         ORDER BY id DESC`).all(chatId);
    return rows.map(mapRow);
  }
  updatePrompt(id, prompt) {
    this.db.query(`UPDATE autonomous_jobs SET prompt = ?, agent_prompt = CASE WHEN job_type = 'hybrid' THEN ? ELSE agent_prompt END, updated_at = ? WHERE id = ?`).run(prompt, prompt, nowIso(), id);
    const job = this.getJobById(id);
    if (!job)
      throw new Error(`Autonomous job not found: ${id}`);
    return job;
  }
  updateSchedule(id, scheduleInput) {
    const schedule = normalizeSchedule(scheduleInput);
    if (schedule.scheduleMode === "once") {
      this.db.query(`UPDATE autonomous_jobs SET schedule_mode = ?, run_at_unix = ?, interval_sec = ?, cron_expr = ?, max_runs = COALESCE(max_runs, 1), updated_at = ? WHERE id = ?`).run(schedule.scheduleMode, schedule.runAtUnix, schedule.intervalSec, schedule.cronExpr, nowIso(), id);
    } else {
      this.db.query(`UPDATE autonomous_jobs SET schedule_mode = ?, run_at_unix = ?, interval_sec = ?, cron_expr = ?, updated_at = ? WHERE id = ?`).run(schedule.scheduleMode, schedule.runAtUnix, schedule.intervalSec, schedule.cronExpr, nowIso(), id);
    }
    const job = this.getJobById(id);
    if (!job)
      throw new Error(`Autonomous job not found: ${id}`);
    return job;
  }
  setEnabled(id, enabled) {
    this.db.query(`UPDATE autonomous_jobs SET enabled = ?, updated_at = ? WHERE id = ?`).run(enabled ? 1 : 0, nowIso(), id);
    const job = this.getJobById(id);
    if (!job)
      throw new Error(`Autonomous job not found: ${id}`);
    return job;
  }
  deleteJob(id) {
    const result = this.db.query(`DELETE FROM autonomous_jobs WHERE id = ?`).run(id);
    return result.changes > 0;
  }
  recordSuccessfulRun(id) {
    const job = this.getJobById(id);
    if (!job)
      throw new Error(`Autonomous job not found: ${id}`);
    const nextRunCount = job.runCount + 1;
    if (job.maxRuns !== null && nextRunCount >= job.maxRuns) {
      this.deleteJob(id);
      return { deleted: true, job: null, runCount: nextRunCount };
    }
    this.db.query(`UPDATE autonomous_jobs SET run_count = ?, updated_at = ? WHERE id = ?`).run(nextRunCount, nowIso(), id);
    const updatedJob = this.getJobById(id);
    if (!updatedJob)
      throw new Error(`Autonomous job not found: ${id}`);
    return { deleted: false, job: updatedJob, runCount: nextRunCount };
  }
  listDueJobs(nowUnix, limit3) {
    if (limit3 <= 0)
      return [];
    const rows = this.db.query(`SELECT${AUTONOMOUS_JOB_COLUMNS}
         FROM autonomous_jobs
         WHERE enabled = 1
         ORDER BY id ASC`).all();
    const dueJobs = [];
    for (const row of rows) {
      const job = mapRow(row);
      if (job.maxRuns !== null && job.runCount >= job.maxRuns) {
        continue;
      }
      const schedule = normalizeSchedule({
        scheduleMode: job.scheduleMode,
        runAtUnix: job.runAtUnix,
        intervalSec: job.intervalSec,
        cronExpr: job.cronExpr,
        lastFinishedAt: job.lastFinishedAt
      });
      const anchor = toUnixAnchor(job.createdAt, job.lastFinishedAt);
      if (isScheduleDue(schedule, anchor, nowUnix)) {
        dueJobs.push(job);
      }
      if (dueJobs.length >= limit3)
        break;
    }
    return dueJobs;
  }
  markRunStarted(id, nowUnix) {
    this.db.query(`UPDATE autonomous_jobs SET last_run_at = ?, last_status = ?, last_error = NULL, updated_at = ? WHERE id = ?`).run(nowUnix, "running", nowIso(), id);
    const job = this.getJobById(id);
    if (!job)
      throw new Error(`Autonomous job not found: ${id}`);
    return job;
  }
  markRunFinished(id, nowUnix, status, error3) {
    this.db.query(`UPDATE autonomous_jobs SET last_finished_at = ?, last_status = ?, last_error = ?, updated_at = ? WHERE id = ?`).run(nowUnix, status, error3, nowIso(), id);
    const job = this.getJobById(id);
    if (!job)
      throw new Error(`Autonomous job not found: ${id}`);
    return job;
  }
}

// src/cron/autonomous.ts
function toErrorMessage(error3) {
  return error3 instanceof Error ? error3.message : String(error3);
}
async function sendTelegramText(bot, chatId, text, errorLabel) {
  let sent = true;
  for (const chunk of splitTelegramMessage(text)) {
    await bot.api.sendMessage(chatId, chunk).catch((error3) => {
      sent = false;
      console.error(errorLabel, error3);
    });
  }
  return sent;
}
function logMemoryUpdateEvent(event, details) {
  console.log(`[memory-update:${event}]`, details);
}
async function reportMemoryUpdateProgress(reporter, event) {
  logMemoryUpdateEvent(`${event.stage}-${event.status}`, event);
  try {
    await emitMemoryUpdateProgress(reporter, event);
  } catch (error3) {
    console.error("Failed to report memory update progress", {
      event,
      error: toErrorMessage(error3)
    });
  }
}
async function runOneAutonomousJob(input) {
  const now = input.nowUnix ?? unixNow();
  const finishedAt = input.finishedUnix ?? unixNow();
  const jobService = new AutonomousJobService(input.db);
  jobService.markRunStarted(input.job.id, now);
  try {
    if (input.job.jobType === "hybrid" && input.job.messageText.trim()) {
      const sent2 = await sendTelegramText(input.bot, input.job.chatId, input.job.messageText, `Failed to send hybrid job text #${input.job.id}`);
      if (!sent2)
        throw new Error(`Failed to send hybrid job text #${input.job.id}`);
    }
    const agentPrompt = input.job.jobType === "hybrid" && input.job.agentPrompt.trim() ? input.job.agentPrompt : input.job.prompt;
    const answer = await (input.runAgent ?? runReactAgent)({
      chatId: input.job.chatId,
      userId: input.job.userId,
      input: `[AUTONOMOUS_JOB #${input.job.id}] ${agentPrompt}`,
      memory: input.memory,
      registry: input.registry,
      llm: input.llm,
      mode: "autonomous"
    });
    const text = `\uD83E\uDD16 Autonomous job #${input.job.id}

${truncateText(answer, 3500)}`;
    const sent = await sendTelegramText(input.bot, input.job.chatId, text, `Failed to send autonomous job #${input.job.id}`);
    if (!sent)
      throw new Error(`Failed to send autonomous job #${input.job.id}`);
    jobService.markRunFinished(input.job.id, finishedAt, "success", null);
    const completion = jobService.recordSuccessfulRun(input.job.id);
    return { job: completion.job, answer, deleted: completion.deleted, runCount: completion.runCount };
  } catch (error3) {
    const message = toErrorMessage(error3);
    jobService.markRunFinished(input.job.id, finishedAt, "error", message);
    const failureText = `\uD83E\uDD16 Autonomous job #${input.job.id} failed

${truncateText(message, 3500)}`;
    await sendTelegramText(input.bot, input.job.chatId, failureText, `Failed to send autonomous job failure #${input.job.id}`);
    throw error3;
  }
}
async function runOneMemoryUpdateNow(input) {
  const source = input.source ?? "scheduler";
  const now = input.nowUnix ?? unixNow();
  const startedAtMs = Date.now();
  input.settings.markRunStarted(input.userId, now);
  await reportMemoryUpdateProgress(input.onProgress, {
    source,
    userId: input.userId,
    stage: "run",
    status: "start",
    startedAtUnix: now
  });
  try {
    const maintenanceResult = await input.memory.runMaintenanceForUser(input.userId, true, {
      source,
      onProgress: (event) => reportMemoryUpdateProgress(input.onProgress, event)
    });
    const finishedAt = input.finishedUnix ?? unixNow();
    const finished = input.settings.markRunFinished(input.userId, finishedAt, "success", null);
    await reportMemoryUpdateProgress(input.onProgress, {
      source,
      userId: input.userId,
      stage: "run",
      status: "complete",
      startedAtUnix: now,
      finishedAtUnix: finishedAt,
      durationMs: Date.now() - startedAtMs,
      createdAtoms: maintenanceResult.l1Created,
      scenarioId: maintenanceResult.l2ScenarioId,
      personaUpdated: maintenanceResult.personaUpdated
    });
    return { settings: finished, maintenanceResult };
  } catch (error3) {
    const message = toErrorMessage(error3);
    const finishedAt = input.finishedUnix ?? unixNow();
    input.settings.markRunFinished(input.userId, finishedAt, "error", message);
    await reportMemoryUpdateProgress(input.onProgress, {
      source,
      userId: input.userId,
      stage: "run",
      status: "error",
      startedAtUnix: now,
      finishedAtUnix: finishedAt,
      durationMs: Date.now() - startedAtMs,
      error: message
    });
    throw error3;
  }
}

// src/bot/conversations/memory-update-runner.ts
var activeMemoryUpdateUsers = new Set;
function toErrorMessage2(error3) {
  return error3 instanceof Error ? error3.message : String(error3);
}
async function safeSendMemoryUpdateMessage(input, text) {
  try {
    await input.sendMessage(text);
  } catch (error3) {
    console.error("Telegram memory update message send failed", {
      userId: input.userId,
      error: error3
    });
  }
}
function formatMemoryUpdateProgressMessage(event) {
  if (event.stage === "run")
    return null;
  if (event.stage === "l1" && event.status === "start")
    return "L1 dimulai...";
  if (event.stage === "l1" && event.status === "complete")
    return `L1 selesai: ${event.createdAtoms ?? 0} atom dibuat.`;
  if (event.stage === "l1" && event.status === "skip")
    return "L1 dilewati: tidak ada percakapan baru.";
  if (event.stage === "l2" && event.status === "start")
    return "L2 dimulai...";
  if (event.stage === "l2" && event.status === "complete")
    return `L2 selesai: scenario #${event.scenarioId}.`;
  if (event.stage === "l2" && event.status === "skip")
    return event.reason === "no_atoms" ? "L2 dilewati: tidak ada atom." : "L2 dilewati.";
  if (event.stage === "l3" && event.status === "start")
    return "L3 dimulai...";
  if (event.stage === "l3" && event.status === "complete")
    return `L3 selesai: persona ${event.personaUpdated ? "updated" : "tidak berubah"}.`;
  if (event.stage === "l3" && event.status === "skip")
    return "L3 dilewati.";
  if (event.status === "error")
    return `Memory update gagal di ${event.stage.toUpperCase()}: ${event.error ?? "unknown error"}`;
  return null;
}
function formatMemoryUpdateFinalMessage(result) {
  return [
    "Memory update selesai.",
    `L1=${result.l1Created} atom,`,
    `L2=${result.l2ScenarioId ? `scenario #${result.l2ScenarioId}` : "dilewati"},`,
    `L3=${result.personaUpdated ? "updated" : "dilewati"}.`
  ].join(" ");
}
async function startTelegramMemoryUpdateRun(input) {
  if (activeMemoryUpdateUsers.has(input.userId)) {
    console.log("[memory-update:run-skip]", {
      source: "telegram",
      userId: input.userId,
      reason: "already_running"
    });
    return { status: "already-running" };
  }
  activeMemoryUpdateUsers.add(input.userId);
  try {
    await input.sendMessage("Memory update dimulai...");
  } catch (error3) {
    activeMemoryUpdateUsers.delete(input.userId);
    throw error3;
  }
  const runNow = input.runNow ?? runOneMemoryUpdateNow;
  const completion = (async () => {
    try {
      const result = await runNow({
        memory: input.memory,
        settings: input.settings,
        userId: input.userId,
        source: "telegram",
        onProgress: async (event) => {
          const message = formatMemoryUpdateProgressMessage(event);
          if (message)
            await safeSendMemoryUpdateMessage(input, message);
        }
      });
      await safeSendMemoryUpdateMessage(input, formatMemoryUpdateFinalMessage(result.maintenanceResult));
    } catch (error3) {
      await safeSendMemoryUpdateMessage(input, `Memory update gagal: ${toErrorMessage2(error3)}`);
    } finally {
      activeMemoryUpdateUsers.delete(input.userId);
    }
  })();
  completion.catch((error3) => {
    console.error("Telegram memory update background task failed", error3);
  });
  return { status: "started", completion };
}

// src/bot/conversations/waits.ts
async function waitForCallbackData(conversation, isExpectedData) {
  const action = await conversation.waitFor("callback_query:data", { next: true });
  if (!isExpectedData(action.callbackQuery.data)) {
    await conversation.skip({ next: true });
  }
  return action;
}
async function waitForTextInput(conversation) {
  const messageCtx = await conversation.waitFor("message:text", { next: true });
  if (messageCtx.message.text.startsWith("/")) {
    await conversation.skip({ next: true });
  }
  return messageCtx;
}

